    long result;

    /*
     * Hacky MIPS syscall approach:
     * - Syscall number goes in $v0 (register 2)
     * - First four arguments go in $a0-$a3 (registers 4-7)
     * - Additional arguments go in $t0-$t1 (registers 8-9)
     * - Result comes back in $v0 (register 2)
