    __asm__ volatile(
        /* Load syscall number into $v0 */
        "move $v0, %1\n\t"

        /* Load first four arguments into $a0-$a3 */
        "move $a0, %2\n\t"
        "move $a1, %3\n\t"
        "move $a2, %4\n\t"
        "move $a3, %5\n\t"

