/*
 * vm.js - A MIPS32r2 (little-endian) interpreter that runs the freestanding
 * `doomgeneric_mips` ELF binary, implements its custom syscall ABI, and saves
 * rendered DOOM frames to disk one at a time as BMP files.
 *
 * Usage:  node vm.js [path-to-elf]
 *
 * The binary uses an x86_64-style syscall NUMBERING placed in $v0 with args in
 * $a0-$a3,$t0,$t1 and the `syscall` instruction (see my_stdlib.c real_syscall6).
 * Only a handful of syscalls ever reach a real `syscall` instruction:
 *   - write(fd=1)  -> stdout
 *   - open/lseek/read/close for "doom.wad" (loaded into the guest's fake FS)
 *   - exit, time
 * All other file I/O is handled inside the guest by an in-memory "fake fs", so
 * the frame BMP that DOOM writes to /tmp/frame.bmp never hits a real syscall.
 * We therefore capture frames by hooking DG_DrawFrame and reading the guest's
 * screen buffer directly, reproducing writeBMPFile() byte-for-byte.
 */

'use strict';
const fs = require('fs');
const path = require('path');

