const MAX_FRAMES = process.env.DOOM_MAX_FRAMES !== undefined
  ? parseInt(process.env.DOOM_MAX_FRAMES, 10)
  : 3;
const MAX_INSN = process.env.DOOM_MAX_INSN ? parseInt(process.env.DOOM_MAX_INSN, 10) : 0;

// Known symbol addresses (from the ELF symbol table).
const A_DG_DrawFrame = 0x4395e4;   // hook point: frame is ready in DG_ScreenBuffer
const A_DG_ScreenBuffer = 0x4b0a40; // global pointer (uint32) to the pixel buffer
const A_gp = 0x47d090;              // _gp
const RESX = 640, RESY = 400;
const FRAME_BYTES = RESX * RESY * 4;

// Guest memory: identity-mapped, base 0. Covers text/data/bss (_end=0x404b1790)
// plus a stack that grows down from near the top.
const MEM_SIZE = 0x41000000; // ~1.09 GB, lazily backed by calloc (low RSS)
const INIT_SP = 0x40fffff0;

// ----------------------------------------------------------------------------
// ELF loader
// ----------------------------------------------------------------------------
const elf = fs.readFileSync(ELF_PATH);
if (!(elf[0] === 0x7f && elf[1] === 0x45 && elf[2] === 0x4c && elf[3] === 0x46)) {
  throw new Error('not an ELF file: ' + ELF_PATH);
}
const edv = new DataView(elf.buffer, elf.byteOffset, elf.length);
const entry = edv.getUint32(24, true);
const phoff = edv.getUint32(28, true);
const phentsize = edv.getUint16(42, true);
const phnum = edv.getUint16(44, true);

const mem = Buffer.alloc(MEM_SIZE); // calloc: zero-filled, lazily paged
const u8 = new Uint8Array(mem.buffer, mem.byteOffset, MEM_SIZE);
const dv = new DataView(mem.buffer, mem.byteOffset, MEM_SIZE);

for (let i = 0; i < phnum; i++) {
  const o = phoff + i * phentsize;
  const type = edv.getUint32(o, true);
  if (type !== 1) continue; // PT_LOAD
  const off = edv.getUint32(o + 4, true);
  const vaddr = edv.getUint32(o + 8, true);
  const filesz = edv.getUint32(o + 16, true);
  elf.copy(mem, vaddr, off, off + filesz);
