  const t3 = c2 + ahbh;
  let lo = (lo16 | (mid << 16)) >>> 0;
  let hi = t3 >>> 0;
  if (signed) {
    if (a < 0) hi = (hi - bu) >>> 0;
    if (b < 0) hi = (hi - au) >>> 0;
  }
  return [hi, lo];
}

// ----------------------------------------------------------------------------
// Host file descriptors (only used for the real doom.wad)
// ----------------------------------------------------------------------------
const hostFds = new Map(); // guestFd -> {fd, pos, size}
let nextGuestFd = 100;

function readCString(addr) {
  let s = '';
  addr >>>= 0;
  while (u8[addr] !== 0) { s += String.fromCharCode(u8[addr]); addr++; }
  return s;
}

function resolveWad(name) {
  const cands = [name, path.join(process.cwd(), name), path.join(__dirname, name),
    path.join('/app', name)];
  for (const c of cands) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return name;
}

// ----------------------------------------------------------------------------
// Frame saving
// ----------------------------------------------------------------------------
let savedFrames = 0;
const BMP_HDR = 54;
function saveFrame() {
  const P = dv.getUint32(A_DG_ScreenBuffer, true) >>> 0;
  if (P === 0 || P + FRAME_BYTES > MEM_SIZE) return;
  const fileSize = BMP_HDR + FRAME_BYTES;
  const out = Buffer.alloc(fileSize);
  // BMP file header + DIB header, matching writeBMPFile() exactly
  out[0] = 0x42; out[1] = 0x4d;                 // 'BM'
  out.writeUInt32LE(fileSize, 2);               // file size
  out.writeUInt32LE(0, 6);                      // reserved
  out.writeUInt32LE(BMP_HDR, 10);               // pixel data offset
  out.writeUInt32LE(40, 14);                    // DIB header size
  out.writeInt32LE(RESX, 18);                   // width
  out.writeInt32LE(-RESY, 22);                  // height (top-down)
  out.writeUInt16LE(1, 26);                     // planes
  out.writeUInt16LE(32, 28);                    // bits per pixel
  out.writeUInt32LE(0, 30);                     // compression
  out.writeUInt32LE(FRAME_BYTES, 34);           // image size
  // remaining header fields are already zero
  u8.subarray(P, P + FRAME_BYTES).forEach; // (noop reference)
  mem.copy(out, BMP_HDR, P, P + FRAME_BYTES);   // raw pixel copy (guest BGRA/RGBA)

  const name = path.join(OUT_DIR, 'frame_' + String(savedFrames).padStart(4, '0') + '.bmp');
  fs.writeFileSync(name, out);
  try { fs.writeFileSync('/tmp/frame.bmp', out); } catch (e) {}
  savedFrames++;
  process.stderr.write('[vm] saved ' + name + '\n');
  if (MAX_FRAMES > 0 && savedFrames >= MAX_FRAMES) {
    process.stderr.write('[vm] reached frame limit, exiting\n');
    process.exit(0);
  }
}

// ----------------------------------------------------------------------------
// Syscalls (custom ABI, x86_64-style numbers)
// ----------------------------------------------------------------------------
const SYS_read = 0, SYS_write = 1, SYS_open = 2, SYS_close = 3, SYS_lseek = 8;
const SYS_exit = 60, SYS_time = 201;

function doSyscall() {
  const num = r[2] >>> 0;
  const a0 = r[4], a1 = r[5], a2 = r[6], a3 = r[7];
  let ret = 0;
  switch (num) {
    case SYS_write: {
      const fd = a0 >>> 0, buf = a1 >>> 0, cnt = a2 >>> 0;
      if (fd === 1 || fd === 0 || fd === 2) {
        const stream = fd === 2 ? process.stderr : process.stdout;
        stream.write(Buffer.from(mem.subarray(buf, buf + cnt)));
        ret = cnt;
      } else { ret = cnt; }
      break;
    }
    case SYS_open: {
      const p = resolveWad(readCString(a0));
      try {
        const fd = fs.openSync(p, 'r');
        const size = fs.fstatSync(fd).size;
        const g = nextGuestFd++;
        hostFds.set(g, { fd, pos: 0, size });
        ret = g;
      } catch (e) { ret = -2; }
      break;
    }
    case SYS_read: {
      const g = hostFds.get(a0 >>> 0);
      if (!g) { ret = 0; break; }
      const buf = a1 >>> 0, cnt = a2 >>> 0;
      const tmp = Buffer.alloc(cnt);
      const n = fs.readSync(g.fd, tmp, 0, cnt, g.pos);
      tmp.copy(mem, buf, 0, n);
      g.pos += n;
      ret = n;
      break;
    }
    case SYS_lseek: {
      const g = hostFds.get(a0 >>> 0);
      if (!g) { ret = -1; break; }
      const off = a1 | 0, whence = a2 | 0;
      if (whence === 0) g.pos = off;            // SEEK_SET
      else if (whence === 1) g.pos += off;      // SEEK_CUR
      else if (whence === 2) g.pos = g.size + off; // SEEK_END
      ret = g.pos;
      break;
    }
    case SYS_close: {
      const g = hostFds.get(a0 >>> 0);
      if (g) { try { fs.closeSync(g.fd); } catch (e) {} hostFds.delete(a0 >>> 0); }
      ret = 0;
      break;
    }
    case SYS_time: {
      const t = Math.floor(Date.now() / 1000);
      if ((a0 >>> 0) !== 0) dv.setUint32(a0 >>> 0, t, true);
      ret = t;
      break;
    }
    case SYS_exit: {
      process.stdout.write('');
      process.exit(a0 & 0xff);
      break;
    }
    default:
      // Unhandled real syscall: return 0 and keep going.
      ret = 0;
      break;
  }
  r[2] = ret | 0;
}

// ----------------------------------------------------------------------------
// Main interpreter loop
// ----------------------------------------------------------------------------
let insnCount = 0;
function run() {
  for (;;) {
    const thisPc = pc;
    if (thisPc === A_DG_DrawFrame) saveFrame();

    const inst = dv.getUint32(thisPc, true);
    pc = nextPc;
    nextPc = (pc + 4) >>> 0;

    const op = inst >>> 26;
    const rs = (inst >>> 21) & 31;
    const rt = (inst >>> 16) & 31;
    const rd = (inst >>> 11) & 31;
    const sa = (inst >>> 6) & 31;
    const funct = inst & 63;
    const imm = inst & 0xffff;
    const simm = (imm << 16) >> 16;

    switch (op) {
      case 0x00: { // SPECIAL
        switch (funct) {
          case 0x00: r[rd] = r[rt] << sa; break; // sll
          case 0x02: // srl / rotr
            if ((inst >>> 21) & 1) r[rd] = sa ? ((r[rt] >>> sa) | (r[rt] << (32 - sa))) : r[rt];
            else r[rd] = r[rt] >>> sa;
            break;
          case 0x03: r[rd] = r[rt] >> sa; break; // sra
          case 0x04: r[rd] = r[rt] << (r[rs] & 31); break; // sllv
          case 0x06: { // srlv / rotrv
            const sh = r[rs] & 31;
            if ((inst >>> 6) & 1) r[rd] = sh ? ((r[rt] >>> sh) | (r[rt] << (32 - sh))) : r[rt];
            else r[rd] = r[rt] >>> sh;
            break;
          }
          case 0x07: r[rd] = r[rt] >> (r[rs] & 31); break; // srav
          case 0x08: nextPc = r[rs] >>> 0; break; // jr
          case 0x09: r[rd] = (thisPc + 8) | 0; nextPc = r[rs] >>> 0; break; // jalr
          case 0x0a: if (r[rt] === 0) r[rd] = r[rs]; break; // movz
          case 0x0b: if (r[rt] !== 0) r[rd] = r[rs]; break; // movn
          case 0x0c: doSyscall(); break; // syscall
          case 0x0d: throw new Error('break at 0x' + thisPc.toString(16)); // break
          case 0x0f: break; // sync
          case 0x10: r[rd] = HI; break; // mfhi
          case 0x11: HI = r[rs]; break; // mthi
          case 0x12: r[rd] = LO; break; // mflo
          case 0x13: LO = r[rs]; break; // mtlo
          case 0x18: { const m = mul64(r[rs], r[rt], true); HI = m[0] | 0; LO = m[1] | 0; break; } // mult
          case 0x19: { const m = mul64(r[rs], r[rt], false); HI = m[0] | 0; LO = m[1] | 0; break; } // multu
          case 0x1a: { // div
            const b = r[rt];
            if (b !== 0) { LO = (Math.trunc(r[rs] / b)) | 0; HI = (r[rs] % b) | 0; }
            break;
          }
          case 0x1b: { // divu
            const au = r[rs] >>> 0, bu = r[rt] >>> 0;
            if (bu !== 0) { LO = (Math.floor(au / bu)) | 0; HI = (au % bu) | 0; }
            break;
          }
          case 0x20: case 0x21: r[rd] = (r[rs] + r[rt]) | 0; break; // add/addu
          case 0x22: case 0x23: r[rd] = (r[rs] - r[rt]) | 0; break; // sub/subu
          case 0x24: r[rd] = r[rs] & r[rt]; break; // and
          case 0x25: r[rd] = r[rs] | r[rt]; break; // or
          case 0x26: r[rd] = r[rs] ^ r[rt]; break; // xor
          case 0x27: r[rd] = ~(r[rs] | r[rt]); break; // nor
          case 0x2a: r[rd] = (r[rs] < r[rt]) ? 1 : 0; break; // slt
          case 0x2b: r[rd] = ((r[rs] >>> 0) < (r[rt] >>> 0)) ? 1 : 0; break; // sltu
          case 0x30: case 0x31: case 0x32: case 0x33: case 0x34: case 0x36:
            break; // traps (tge/tgeu/tlt/tltu/teq/tne): ignore
          default: throw new Error('unknown SPECIAL funct 0x' + funct.toString(16) + ' @0x' + thisPc.toString(16));
        }
        break;
      }
      case 0x01: { // REGIMM
        const cond = r[rs];
        const link = rt & 0x10;
        const take = ((rt & 1) === 0) ? (cond < 0) : (cond >= 0); // bltz vs bgez
        if (link) r[31] = (thisPc + 8) | 0;
        if (take) nextPc = (pc + (simm << 2)) >>> 0;
        break;
      }
      case 0x02: nextPc = ((pc & 0xf0000000) | ((inst & 0x3ffffff) << 2)) >>> 0; break; // j
      case 0x03: r[31] = (thisPc + 8) | 0; nextPc = ((pc & 0xf0000000) | ((inst & 0x3ffffff) << 2)) >>> 0; break; // jal
      case 0x04: if (r[rs] === r[rt]) nextPc = (pc + (simm << 2)) >>> 0; break; // beq
      case 0x05: if (r[rs] !== r[rt]) nextPc = (pc + (simm << 2)) >>> 0; break; // bne
      case 0x06: if (r[rs] <= 0) nextPc = (pc + (simm << 2)) >>> 0; break; // blez
      case 0x07: if (r[rs] > 0) nextPc = (pc + (simm << 2)) >>> 0; break; // bgtz
      case 0x08: case 0x09: r[rt] = (r[rs] + simm) | 0; break; // addi/addiu
      case 0x0a: r[rt] = (r[rs] < simm) ? 1 : 0; break; // slti
      case 0x0b: r[rt] = ((r[rs] >>> 0) < (simm >>> 0)) ? 1 : 0; break; // sltiu
      case 0x0c: r[rt] = r[rs] & imm; break; // andi
      case 0x0d: r[rt] = r[rs] | imm; break; // ori
      case 0x0e: r[rt] = r[rs] ^ imm; break; // xori
      case 0x0f: r[rt] = imm << 16; break; // lui
      case 0x11: cop1(inst, rs, rt, rd, sa, funct, thisPc); break; // COP1
      case 0x1c: { // SPECIAL2
        if (funct === 0x02) r[rd] = Math.imul(r[rs], r[rt]); // mul
        else if (funct === 0x20 || funct === 0x21) r[rd] = Math.clz32(r[rs]); // clz/clo(approx)
        else if (funct === 0x00) { const m = mul64(r[rs], r[rt], true); const lo = (LO >>> 0) + (m[1] >>> 0); LO = lo | 0; HI = (HI + m[0] + (lo > 0xffffffff ? 1 : 0)) | 0; } // madd
        else throw new Error('unknown SPECIAL2 funct 0x' + funct.toString(16) + ' @0x' + thisPc.toString(16));
        break;
      }
      case 0x1f: { // SPECIAL3
        if (funct === 0x00) { // ext
          const size = rd + 1, posn = sa;
          const mask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
          r[rt] = (r[rs] >>> posn) & mask;
        } else if (funct === 0x04) { // ins
          const msb = rd, lsb = sa, size = msb - lsb + 1;
          const mask = ((size >= 32 ? 0xffffffff : ((1 << size) - 1)) << lsb) >>> 0;
          r[rt] = ((r[rt] & ~mask) | ((r[rs] << lsb) & mask)) | 0;
        } else if (funct === 0x20) { // BSHFL
          if (sa === 0x10) r[rd] = (r[rt] << 24) >> 24;      // seb
          else if (sa === 0x18) r[rd] = (r[rt] << 16) >> 16; // seh
          else if (sa === 0x02) { const x = r[rt]; r[rd] = (((x & 0x00ff00ff) << 8) | ((x >>> 8) & 0x00ff00ff)) | 0; } // wsbh
          else throw new Error('unknown BSHFL sa 0x' + sa.toString(16) + ' @0x' + thisPc.toString(16));
        } else throw new Error('unknown SPECIAL3 funct 0x' + funct.toString(16) + ' @0x' + thisPc.toString(16));
        break;
      }
      case 0x20: r[rt] = (dv.getInt8((r[rs] + simm) >>> 0)); break; // lb
      case 0x21: r[rt] = (dv.getInt16((r[rs] + simm) >>> 0, true)); break; // lh
      case 0x22: r[rt] = lwl((r[rs] + simm) >>> 0, r[rt]); break; // lwl
      case 0x23: r[rt] = dv.getInt32((r[rs] + simm) >>> 0, true); break; // lw
      case 0x24: r[rt] = dv.getUint8((r[rs] + simm) >>> 0); break; // lbu
      case 0x25: r[rt] = dv.getUint16((r[rs] + simm) >>> 0, true); break; // lhu
      case 0x26: r[rt] = lwr((r[rs] + simm) >>> 0, r[rt]); break; // lwr
      case 0x28: dv.setUint8((r[rs] + simm) >>> 0, r[rt] & 0xff); break; // sb
      case 0x29: dv.setUint16((r[rs] + simm) >>> 0, r[rt] & 0xffff, true); break; // sh
      case 0x2a: swl((r[rs] + simm) >>> 0, r[rt]); break; // swl
      case 0x2b: dv.setUint32((r[rs] + simm) >>> 0, r[rt] >>> 0, true); break; // sw
      case 0x2e: swr((r[rs] + simm) >>> 0, r[rt]); break; // swr
      case 0x31: f[rt] = dv.getInt32((r[rs] + simm) >>> 0, true); break; // lwc1
      case 0x35: { const a = (r[rs] + simm) >>> 0; f[rt] = dv.getInt32(a, true); f[rt + 1] = dv.getInt32(a + 4, true); break; } // ldc1
      case 0x39: dv.setInt32((r[rs] + simm) >>> 0, f[rt], true); break; // swc1
      case 0x3d: { const a = (r[rs] + simm) >>> 0; dv.setInt32(a, f[rt], true); dv.setInt32(a + 4, f[rt + 1], true); break; } // sdc1
      case 0x30: r[rt] = dv.getInt32((r[rs] + simm) >>> 0, true); break; // ll (treat as lw)
      case 0x38: dv.setUint32((r[rs] + simm) >>> 0, r[rt] >>> 0, true); r[rt] = 1; break; // sc (always succeed)
      default: throw new Error('unknown opcode 0x' + op.toString(16) + ' inst 0x' + (inst >>> 0).toString(16) + ' @0x' + thisPc.toString(16));
    }
    r[0] = 0;

    if (MAX_INSN && ++insnCount >= MAX_INSN) {
      process.stderr.write('[vm] instruction limit reached @0x' + pc.toString(16) + '\n');
      return;
    }
  }
}

// Unaligned load/store helpers (little-endian)
function lwl(addr, old) {
  const base = addr & ~3, k = addr & 3;
  const W = dv.getUint32(base, true);
  const shift = (3 - k) * 8;
  const mask = shift ? (((1 << shift) >>> 0) - 1) : 0;
  return ((W << shift) | (old & mask)) | 0;
}
function lwr(addr, old) {
  const base = addr & ~3, k = addr & 3;
  const W = dv.getUint32(base, true);
  const shift = k * 8;
  const keep = (~(0xffffffff >>> shift)) >>> 0;
  return ((W >>> shift) | (old & keep)) | 0;
}
function swl(addr, val) {
  const base = addr & ~3, k = addr & 3;
  const W = dv.getUint32(base, true);
  const shift = (3 - k) * 8;
  const keep = (~(0xffffffff >>> shift)) >>> 0;
  dv.setUint32(base, ((val >>> shift) | (W & keep)) >>> 0, true);
}
function swr(addr, val) {
  const base = addr & ~3, k = addr & 3;
  const W = dv.getUint32(base, true);
  const shift = k * 8;
  const mask = shift ? (((1 << shift) >>> 0) - 1) : 0;
  dv.setUint32(base, ((val << shift) | (W & mask)) >>> 0, true);
}

// ----------------------------------------------------------------------------
// COP1 (FPU)
// ----------------------------------------------------------------------------
function cop1(inst, fmt, ft, fs, fd, funct, thisPc) {
  switch (fmt) {
    case 0x00: r[ft] = f[fs]; return;        // mfc1
    case 0x02: r[ft] = (fs === 31) ? (fcc << 23) : 0; return; // cfc1
    case 0x03: r[ft] = f[fs + 1]; return;    // mfhc1
    case 0x04: f[fs] = r[ft]; return;        // mtc1
    case 0x06: return;                       // ctc1 (ignore)
    case 0x07: f[fs + 1] = r[ft]; return;    // mthc1
    case 0x08: { // BC1F / BC1T
      const tf = ft & 1;
      const simm = (inst & 0xffff) << 16 >> 16;
      if (fcc === tf) nextPc = (pc + (simm << 2)) >>> 0;
      return;
    }
    case 0x10: fpArith('S', ft, fs, fd, funct, inst, thisPc); return; // single
    case 0x11: fpArith('D', ft, fs, fd, funct, inst, thisPc); return; // double
    case 0x14: fpArith('W', ft, fs, fd, funct, inst, thisPc); return; // word
    case 0x15: fpArith('L', ft, fs, fd, funct, inst, thisPc); return; // long
    default: throw new Error('unknown COP1 fmt 0x' + fmt.toString(16) + ' @0x' + thisPc.toString(16));
  }
}

function fpArith(fmt, ft, fs, fd, funct, inst, thisPc) {
  // Conversions from integer formats
  if (fmt === 'W' || fmt === 'L') {
    const iv = (fmt === 'W') ? f[fs] : Number(BigInt.asIntN(64, (BigInt(f[fs + 1] >>> 0) << 32n) | BigInt(f[fs] >>> 0)));
    switch (funct) {
      case 0x20: setF32(fd, iv); return; // cvt.s
      case 0x21: setF64(fd, iv); return; // cvt.d
      default: throw new Error('unknown cvt from ' + fmt + ' funct 0x' + funct.toString(16) + ' @0x' + thisPc.toString(16));
    }
  }

  const single = (fmt === 'S');
  const a = single ? getF32(fs) : getF64(fs);
  const b = single ? getF32(ft) : getF64(ft);
  const put = (v) => single ? setF32(fd, v) : setF64(fd, v);

  if (funct >= 0x30) { // c.cond.fmt
    const cond = funct & 15;
    let res;
    const un = (a !== a) || (b !== b); // NaN
    switch (cond & 7) {
      case 0: res = false; break;              // F
      case 1: res = un; break;                 // UN
      case 2: res = (a === b); break;          // EQ
      case 3: res = un || (a === b); break;    // UEQ
      case 4: res = !un && (a < b); break;     // OLT
      case 5: res = un || (a < b); break;      // ULT
      case 6: res = !un && (a <= b); break;    // OLE
      case 7: res = un || (a <= b); break;     // ULE
    }
    fcc = res ? 1 : 0;
    return;
  }

  switch (funct) {
    case 0x00: put(a + b); return; // add
    case 0x01: put(a - b); return; // sub
    case 0x02: put(a * b); return; // mul
    case 0x03: put(a / b); return; // div
    case 0x04: put(Math.sqrt(a)); return; // sqrt
    case 0x05: put(Math.abs(a)); return; // abs
    case 0x06: single ? (f[fd] = f[fs]) : (f[fd] = f[fs], f[fd + 1] = f[fs + 1]); return; // mov
    case 0x07: put(-a); return; // neg
    case 0x0d: f[fd] = Math.trunc(a) | 0; return; // trunc.w
    case 0x0c: f[fd] = Math.round(a) | 0; return; // round.w
    case 0x0e: f[fd] = Math.ceil(a) | 0; return;  // ceil.w
    case 0x0f: f[fd] = Math.floor(a) | 0; return; // floor.w
    case 0x11: { // movcf (movt/movf)
      const tf = (ft & 1);
      if (fcc === tf) { single ? (f[fd] = f[fs]) : (f[fd] = f[fs], f[fd + 1] = f[fs + 1]); }
      return;
    }
    case 0x12: if (r[ft] === 0) { single ? (f[fd] = f[fs]) : (f[fd] = f[fs], f[fd + 1] = f[fs + 1]); } return; // movz
    case 0x13: if (r[ft] !== 0) { single ? (f[fd] = f[fs]) : (f[fd] = f[fs], f[fd + 1] = f[fs + 1]); } return; // movn
    case 0x20: setF32(fd, a); return; // cvt.s
    case 0x21: setF64(fd, a); return; // cvt.d
    case 0x24: f[fd] = Math.trunc(a) | 0; return; // cvt.w (round-to-zero approx)
    default: throw new Error('unknown fp funct 0x' + funct.toString(16) + ' fmt ' + fmt + ' @0x' + thisPc.toString(16));
  }
}

// ----------------------------------------------------------------------------
process.stderr.write('[vm] entry=0x' + entry.toString(16) + ' sp=0x' + (INIT_SP >>> 0).toString(16) + '\n');
try {
  run();
} catch (e) {
  process.stderr.write('[vm] halted: ' + e.message + '\n');
  process.exit(1);
}

